import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';
import TourForm from '../components/TourForm';
import TourList from '../components/TourList';
import { useAuth } from '../context/AuthContext';

const Tours = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);
  const [editingTour, setEditingTour] = useState(null);
  const [showForm, setShowForm] = useState(false); // 控制全螢幕表單/詳情頁的顯示

  // 1. 抓取所有行程 (Read)
  const fetchTours = async () => {
    try {
      const response = await axiosInstance.get('/api/tours', {
        headers: { Authorization: `Bearer ${user?.token}` },
      });
      setTours(response.data);
    } catch (error) {
      console.error('抓取行程失敗:', error);
    }
  };

  useEffect(() => {
    if (user) fetchTours();
  }, [user]);

  // 2. 處理「點擊行程」：進入編輯/詳情模式
  const handleSelectTour = (tour) => {
    setEditingTour(tour); // 傳入選中的行程資料
    setShowForm(true);    // 開啟全螢幕覆蓋層
  };

  // 3. 處理「+ New」：進入新增模式
  const handleAddNew = () => {
    setEditingTour(null); // 確保是空的，這樣表單才會是空白的
    setShowForm(true);
  };

  // 4. 處理成功後的行為 (新增/編輯/刪除成功後)
  const handleSuccess = () => {
    setShowForm(false);
    setEditingTour(null);
    fetchTours(); // 重新整理列表數據
  };

  return (
    // 外層灰色底，模擬手機置中
    <div className="bg-gray-100 min-h-screen pt-16 pb-10">
      {/* 手機容器：420px 寬度 */}
      <div className="max-w-[420px] mx-auto bg-white min-h-[85vh] shadow-2xl relative overflow-hidden flex flex-col rounded-t-[40px] md:rounded-[40px]">

        {/* Header (標題與 + New 按鈕) */}
        <div className="flex justify-between items-center p-6 border-b bg-white sticky top-0 z-10">
          <h1 className="text-xl font-black text-gray-900 tracking-tight">Order List</h1>
          <button 
            onClick={handleAddNew}
            className="text-emerald-500 font-bold hover:text-emerald-600 transition text-sm"
          >
            + New
          </button>
        </div>

        {/* 內容區：顯示行程清單 */}
        <div className="flex-1 overflow-y-auto p-4 bg-gray-50">
          <div className="flex justify-between items-end mb-4 px-2">
            <h2 className="text-lg font-bold text-gray-800">Inventory</h2>
            <span className="text-xs text-gray-400 font-medium">{tours.length} items</span>
          </div>

          {/* 傳入 handleSelectTour 給清單，讓每一項都可以被點擊 */}
          <TourList 
            tours={tours} 
            setTours={setTours} 
            setEditingTour={handleSelectTour} 
          />
        </div>

        {/* --- 全螢幕表單彈窗 (Overlay) --- */}
        {/* 這就是你要求的：點進去看的「細節/編輯/刪除」頁面 */}
        {showForm && (
          <div className="fixed inset-0 z-[60] flex justify-center bg-black bg-opacity-40 backdrop-blur-sm">
            <div className="w-full max-w-[420px] bg-white h-full overflow-y-auto animate-slide-up">
              <TourForm
                editingTour={editingTour}
                onClose={() => { setShowForm(false); setEditingTour(null); }}
                onSuccess={handleSuccess}
                tours={tours}
                setTours={setTours}
              />
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Tours;
